window.COURSE_LANG = window.COURSE_LANG || {};
window.COURSE_LANG["cdl-general"] = window.COURSE_LANG["cdl-general"] || {};
window.COURSE_LANG["cdl-general"]["es"] = [
  {"id":1,"q":"La razón más importante para inspeccionar tu vehículo es:","opts":["La seguridad para ti y los demás usuarios de la vía","Pasar el tiempo","Mejorar el rendimiento de combustible","Mantener limpia la cabina"],"re":"La seguridad es la razón principal; un defecto puede causar un choque o una avería."},
  {"id":2,"q":"Debes inspeccionar tu vehículo:","opts":["Antes, durante y después de un viaje","Solo una vez al mes","Solo cuando algo se siente mal","Solo en la terminal"],"re":"Haz una inspección previa al viaje, revisiones en ruta y una inspección posterior."},
  {"id":3,"q":"Las llantas del eje delantero (de dirección) deben tener una profundidad de dibujo de al menos:","opts":["2/32 de pulgada","4/32 de pulgada","8/32 de pulgada","No hay mínimo"],"re":"Las llantas delanteras de dirección necesitan al menos 4/32 de pulgada; las demás al menos 2/32."},
  {"id":4,"q":"Las llantas que no son de dirección deben tener una profundidad de dibujo de al menos:","opts":["1/32 de pulgada","2/32 de pulgada","4/32 de pulgada","6/32 de pulgada"],"re":"Las llantas que no son de dirección necesitan al menos 2/32 de pulgada de dibujo."},
  {"id":5,"q":"Con dirección hidráulica, el juego libre del volante no debe superar unas:","opts":["2 pulgadas (unos 10 grados)","6 pulgadas","10 pulgadas","Media vuelta"],"re":"Más de unos 10 grados (cerca de 2 pulgadas en un volante de 20 pulgadas) de juego vuelve insegura la dirección."},
  {"id":6,"q":"Si encuentras un defecto de seguridad durante la inspección, debes:","opts":["Conducir con cuidado de todos modos","Anotarlo para la próxima semana","Ignorarlo si parece menor","Repararlo antes de conducir"],"re":"Un vehículo con un defecto de seguridad no debe conducirse hasta repararlo."},
  {"id":7,"q":"El informe de inspección del vehículo del conductor:","opts":["Fija tu salario","Indica el clima","Informa al transportista sobre los defectos que encontraste","Planea tu ruta"],"re":"El informe avisa al transportista de los problemas para que se reparen."},
  {"id":8,"q":"Mientras conduces, debes vigilar tu vehículo:","opts":["Sin detenerte nunca","Revisando solo el indicador de combustible","Escuchando música","Observando los indicadores y usando tus sentidos para detectar problemas"],"re":"Observa los instrumentos y usa la vista, el olfato, el oído y el tacto para detectar problemas en ruta."},
  {"id":9,"q":"¿Cuál es un defecto de llanta que debes revisar?","opts":["Pintura fresca","Un rin limpio","Guardafangos nuevos","Cortes, abultamientos o presión baja"],"re":"Cortes, abultamientos, presión baja y dibujo gastado pueden causar un reventón."},
  {"id":10,"q":"Para dar reversa con un vehículo pesado de forma segura debes:","opts":["Dar reversa lo más rápido posible","Dar reversa a ciegas y confiar en la suerte","Dar reversa hacia el lado del conductor y usar un ayudante","No usar nunca los espejos"],"re":"Da reversa despacio hacia el lado del conductor, donde puedes ver, con un ayudante y las intermitentes."},
  {"id":11,"q":"Antes de dar reversa debes:","opts":["Simplemente empezar","Solo tocar el claxon","Confiar solo en los espejos","Bajarte y mirar (G.O.A.L.) tu trayectoria"],"re":"Camina alrededor y revisa tu trayectoria antes y durante la reversa."},
  {"id":12,"q":"La mayoría de los camiones pesados cambian de marcha usando:","opts":["Un solo pisón rápido del embrague","El doble embrague (double-clutch)","Sin embrague","El freno de mano"],"re":"El doble embrague es la forma normal de cambiar suavemente la transmisión manual de un camión pesado."},
  {"id":13,"q":"Debes hacer un cambio ascendente:","opts":["Al RPM más bajo posible","Solo al ir cuesta abajo","Antes de que el motor llegue al RPM máximo regulado","Nunca"],"re":"Sube de marcha antes de que el motor se revolucione de más, usando RPM y velocidad."},
  {"id":14,"q":"Debes reducir de marcha (downshift):","opts":["Antes de empezar a bajar una pendiente o antes de una curva","Después de haber empezado a bajar","Solo en terreno plano","Nunca en pendientes"],"re":"Reduce de marcha antes de una bajada o curva para que el motor ayude a controlar la velocidad."},
  {"id":15,"q":"Para acelerar suavemente debes:","opts":["Soltar el embrague de golpe","Pisar a fondo el acelerador","No tocar nunca el embrague","Acelerar poco a poco para que la carga no se mueva"],"re":"Acelerar suave protege la transmisión y evita que la carga se desplace."},
  {"id":16,"q":"La forma correcta de hacer una parada normal es:","opts":["Pisar el freno de forma constante y suave","Frenar de golpe","Usar siempre el freno de mano","Bombear lo más fuerte posible"],"re":"Frena de forma constante y suave para detenerte sin sacudir la carga ni patinar."},
  {"id":17,"q":"Cuando un vehículo largo gira, sus ruedas traseras:","opts":["Recortan y siguen una trayectoria más corta por dentro de la curva","Siguen exactamente la misma trayectoria que las delanteras","Se abren hacia afuera","Se levantan del suelo"],"re":"Las ruedas traseras recortan hacia adentro; abre lo suficiente para que el remolque libre la esquina."},
  {"id":18,"q":"Debes señalar una vuelta:","opts":["En el último segundo","Solo si hay autos cerca","Nunca, para no confundir","Con anticipación y de forma continua durante la vuelta"],"re":"Señala con anticipación y mantén la señal durante la vuelta para que otros entiendan tu intención."},
  {"id":19,"q":"Para avisar a los conductores detrás que reduces por un peligro, puedes:","opts":["Acelerar","Tocar suavemente el pedal del freno para encender las luces de freno","Apagar tus luces","Hacerles señas para que pasen"],"re":"Unos toques suaves encienden las luces de freno y avisan a los de atrás."},
  {"id":20,"q":"Debes mantener los ojos en movimiento y mirar adelante unos:","opts":["Apenas más allá del cofre","Al auto justo adelante","12 a 15 segundos","Al cielo"],"re":"Mirar de 12 a 15 segundos adelante te permite detectar y planear ante peligros a tiempo."},
  {"id":21,"q":"Debes revisar tus espejos:","opts":["Nunca","Con regularidad, y sobre todo antes de cambiar de carril y girar","Solo de noche","Solo estacionado"],"re":"Revisa los espejos con regularidad y antes de cambiar de carril, girar o incorporarte."},
  {"id":22,"q":"Hacer señas a otro conductor para que te rebase es inseguro porque:","opts":["Es ilegal en todas partes","Gasta combustible","Tus espejos tapan la vista","Podrías ser responsable si choca"],"re":"No hagas señas para que otros rebasen; podrías ser responsable si ocurre un choque."},
  {"id":23,"q":"Las zonas ciegas alrededor de un camión grande se llaman:","opts":["No-Zones","Zonas verdes","Zonas seguras","Zonas despejadas"],"re":"Las áreas donde el conductor del camión no ve a otros vehículos son las No-Zones."},
  {"id":24,"q":"A velocidad de autopista, 12 a 15 segundos de distancia de visión adelante equivalen a unos:","opts":["10 pies","Una cuadra","Un cuarto de milla","Dos millas"],"re":"A velocidad de autopista, 12 a 15 segundos son cerca de un cuarto de milla adelante."},
  {"id":25,"q":"Encender los faros durante el día:","opts":["Gasta la batería","Es ilegal","Encandila a otros","Hace que tu vehículo se vea más fácil"],"re":"Estar iluminado ayuda a que otros vean tu vehículo grande, de día o de noche."},
  {"id":26,"q":"Por debajo de 40 mph, la regla práctica de distancia de seguimiento es:","opts":["1 segundo en total","1 segundo por cada 10 pies de largo del vehículo","3 segundos en total","10 segundos en total"],"re":"Deja 1 segundo por cada 10 pies de largo por debajo de 40 mph; suma 1 segundo por encima de 40 mph."},
  {"id":27,"q":"Un vehículo de 60 pies por debajo de 40 mph necesita una distancia de seguimiento de unos:","opts":["1 segundo","2 segundos","6 segundos","12 segundos"],"re":"60 pies entre 10 = 6 segundos de distancia de seguimiento por debajo de 40 mph."},
  {"id":28,"q":"La distancia total de frenado se compone de:","opts":["Solo la distancia de frenado","Distancia de percepción + distancia de reacción + distancia de frenado","Solo el tiempo de reacción","Velocidad por peso"],"re":"Distancia total de frenado = distancia de percepción + distancia de reacción + distancia de frenado."},
  {"id":29,"q":"A 55 mph en pavimento seco, ¿qué distancia necesita aproximadamente un vehículo pesado para detenerse?","opts":["Unos 60 pies","Aproximadamente el largo de un campo de fútbol americano","Unos 10 pies","Cerca de una milla"],"re":"A 55 mph toma unos 6 segundos y aproximadamente el largo de un campo de fútbol americano detenerse."},
  {"id":30,"q":"Comparado con un camión cargado, un camión vacío:","opts":["Siempre se detiene antes","Nunca patina","Puede tardar más en detenerse porque tiene menos tracción","Tiene el mejor frenado de todos"],"re":"Un camión vacío tiene menos tracción y puede necesitar mayor distancia de frenado."},
  {"id":31,"q":"Debes reducir la velocidad para una curva:","opts":["Antes de entrar en ella","En medio de ella","Después de ella","Solo si está mojada"],"re":"Reduce la velocidad antes de la curva y luego acelera suavemente al pasarla."},
  {"id":32,"q":"El desvanecimiento de frenos (brake fade) en una bajada larga se debe a:","opts":["Frenos fríos","Forros nuevos","Una carga ligera","Calor excesivo por abusar de los frenos"],"re":"Mantener los frenos pisados en la bajada los sobrecalienta y causa desvanecimiento o falla."},
  {"id":33,"q":"Antes de descender una pendiente larga y empinada debes:","opts":["Elegir una marcha baja segura antes de empezar a bajar","Poner neutral","Acelerar primero","Bombear los frenos todo el camino"],"re":"Elige una marcha baja antes del descenso para que el motor ayude a mantener la velocidad."},
  {"id":34,"q":"Si tus frenos fallan en una bajada, lo más seguro es:","opts":["Tocar el claxon","Subir a una marcha más alta","Usar una rampa de escape si hay","Ir en neutral por inercia"],"re":"Una rampa de escape está hecha para detener con seguridad a un vehículo sin frenos."},
  {"id":35,"q":"En un camino mojado, reduce tu velocidad en aproximadamente:","opts":["No hace falta cambiar","Un tercio","Acelera en vez de frenar","Un décimo"],"re":"Reduce la velocidad cerca de un tercio en mojado; cerca de la mitad en nieve compacta."},
  {"id":36,"q":"El hidroplaneo puede comenzar a velocidades tan bajas como unas:","opts":["5 mph","30 mph","70 mph","No le pasa a los camiones"],"re":"Con suficiente agua, el hidroplaneo puede empezar cerca de 30 mph; suelta el acelerador."},
  {"id":37,"q":"Con niebla debes usar:","opts":["Luces altas","Luces bajas","Sin luces","Solo las intermitentes a velocidad normal"],"re":"Usa luces bajas con niebla; las altas se reflejan y reducen la visibilidad."},
  {"id":38,"q":"En un cruce de ferrocarril debes:","opts":["Cambiar de marcha sobre las vías","Detenerte sobre las vías si hay tráfico","Cruzar rápido en neutral","Asegurarte de poder cruzarlo por completo antes de empezar"],"re":"Nunca empieces a cruzar si no puedes pasar del todo, y no cambies de marcha sobre las vías."},
  {"id":39,"q":"La mayoría de los patinazos se deben a:","opts":["Conducir demasiado despacio","Buenas llantas","Conducir demasiado rápido para las condiciones","Poco tráfico"],"re":"Conducir demasiado rápido para las condiciones es la causa principal de los patinazos."},
  {"id":40,"q":"Al conducir de noche debes:","opts":["Reducir la velocidad y mantener limpios el parabrisas y las luces","Usar luces altas cerca del tráfico que viene","Acelerar para terminar antes","Seguir de cerca para usar sus luces"],"re":"De noche reduce la velocidad, mantén limpios los vidrios y las luces, y baja las altas ante el tráfico que viene."},
  {"id":41,"q":"En clima muy caluroso, vigila especialmente:","opts":["El hielo negro","Líneas de freno congeladas","La niebla","Reventones de llanta y sobrecalentamiento"],"re":"El calor aumenta el riesgo de reventones y sobrecalentamiento del motor o los frenos; revisa llantas y refrigerante."},
  {"id":42,"q":"Antes de conducir en invierno, asegúrate de que:","opts":["Las ventanas, espejos y luces estén libres de hielo y nieve","Solo funcione la radio","El camión siga sucio","Nunca se lleven cadenas"],"re":"Quita el hielo y la nieve de vidrios, espejos y luces para ver y ser visto."},
  {"id":43,"q":"Si las ruedas motrices se bloquean y la parte trasera empieza a patinar, debes:","opts":["Frenar aún más fuerte","Dejar de frenar y dirigir hacia donde quieres ir","Jalar el freno de mano","Soltar el volante"],"re":"Suelta los frenos para que las ruedas rueden de nuevo y dirige hacia donde quieres ir."},
  {"id":44,"q":"Con frenos antibloqueo (ABS), en una parada de emergencia debes:","opts":["Bombear el pedal","Evitar los frenos","Frenar firme y seguir dirigiendo — no bombear","Usar solo el freno de mano"],"re":"Con ABS, mantén presión firme; el sistema evita el bloqueo y conservas el control de la dirección."},
  {"id":45,"q":"El límite de alcohol en sangre para conducir un vehículo comercial es:","opts":["0.08%","0.05%","0.04%","0.10%"],"re":"Un conductor con CDL está legalmente ebrio a 0.04% de BAC — la mitad del límite para autos."},
  {"id":46,"q":"Es más probable que los conductores sientan sueño:","opts":["Al mediodía","Justo al despertar","En tráfico pesado","Entre la medianoche y el amanecer"],"re":"La fatiga es mayor entre la medianoche y el amanecer; la única cura real es detenerse y dormir."},
  {"id":47,"q":"Si se produce un incendio de carga en el remolque, en general debes:","opts":["Mantener las puertas cerradas, detenerte y pedir ayuda","Abrir las puertas para mirar adentro","Acelerar para apagarlo","Echar agua a un fuego eléctrico"],"re":"Abrir las puertas alimenta el fuego con oxígeno; detente con seguridad y pide ayuda."},
  {"id":48,"q":"La mayoría de los vehículos comerciales llevan un extintor clasificado:","opts":["Solo A","De agua","No se requiere ninguno","B:C (líquidos inflamables y eléctricos)"],"re":"Un extintor B:C cubre los incendios de líquidos inflamables y eléctricos comunes en los vehículos."},
  {"id":49,"q":"Tras detenerte por una emergencia en una autopista dividida, coloca triángulos reflectantes a unos:","opts":["1 pie detrás del camión","Media milla atrás","10, 100 y 200 pies hacia el tráfico que se aproxima","Solo justo detrás del camión"],"re":"Coloca triángulos de advertencia a unos 10, 100 y 200 pies del vehículo hacia el tráfico que se aproxima."},
  {"id":50,"q":"Para un conductor comercial, usar un teléfono de mano mientras conduce está:","opts":["Permitido en cualquier momento","Prohibido","Es obligatorio","Permitido solo de noche"],"re":"Los conductores comerciales no pueden sostener, marcar ni enviar mensajes con un teléfono de mano al conducir."}
];
